// pruneHarnessSessions removes stale .ddx/harness-sessions/*.json files.
// These are opaque runtime scratch written by the harness; DDx does not parse
// their contents. Files modified within defaultExecutionCleanupScratchMinAge
// are preserved to avoid racing with an active harness.
func (m *ExecutionCleanupManager) pruneHarnessSessions(ctx context.Context, summary *ExecutionCleanupSummary, now time.Time) {
	const dirName = "harness-sessions"
	dir := ddxroot.InTree(m.ProjectRoot, dirName)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    dir,
				Class:   "harness_sessions_read",
				Message: err.Error(),
			})
		}
		return
	}

	cutoff := now.Add(-defaultExecutionCleanupScratchMinAge)
	for _, entry := range entries {
		if ctx != nil && ctx.Err() != nil {
			return
		}
		if entry.IsDir() {
			continue
		}
		if !strings.HasSuffix(entry.Name(), ".json") {
			continue
		}
		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    filepath.Join(dir, entry.Name()),
				Class:   "harness_session_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}
		relPath := filepath.ToSlash(filepath.Join(".ddx/"+dirName, entry.Name()))
		path := filepath.Join(dir, entry.Name())
		if !m.DryRun {
			if err := os.Remove(path); err != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    relPath,
					Class:   "harness_session_remove",
					Message: err.Error(),
				})
				continue
			}
		}
		summary.RemovedHarnessSessionFiles++
		bytes := info.Size()
		summary.BytesReclaimed += bytes
		summary.InodesReclaimed++
		class := "removed_harness_session_file"
		if m.DryRun {
			class = "would_remove_harness_session_file"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    relPath,
			Class:   class,
			Message: "stale harness-session scratch",
			Bytes:   bytes,
			Inodes:  1,
		})
	}

	// Remove the directory itself if it is now empty.
	if !m.DryRun && summary.RemovedHarnessSessionFiles > 0 {
		_ = os.Remove(dir) // no-op if non-empty or already absent
	}
}

