// TestCheckpointPreDispatchDirtIgnoresHarnessSessionFiles verifies that an
// untracked .ddx/harness-sessions/*.json file (DDx/Fizeau runtime scratch) is
// not returned by preDispatchCheckpointDirtyPaths, while a real implementation
// file in the same repo is still returned. This is the regression test for the
// Niflheim incident where .ddx/harness-sessions/-926795.json was incorrectly
// surfaced as operator-attention implementation dirt.
func TestCheckpointPreDispatchDirtIgnoresHarnessSessionFiles(t *testing.T) {
	root := t.TempDir()
	runGitInteg(t, root, "init", "-b", "main")
	runGitInteg(t, root, "config", "user.email", "test@ddx.test")
	runGitInteg(t, root, "config", "user.name", "DDx Test")

	seedFile := filepath.Join(root, "seed.txt")
	require.NoError(t, os.WriteFile(seedFile, []byte("seed\n"), 0o644))
	runGitInteg(t, root, "add", "seed.txt")
	runGitInteg(t, root, "commit", "-m", "chore: initial seed")

	// Create harness-session scratch without a .gitignore rule — simulates a
	// project that predates the init.go fix.
	sessionsDir := filepath.Join(root, ".ddx", "harness-sessions")
	require.NoError(t, os.MkdirAll(sessionsDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(sessionsDir, "-926795.json"), []byte("{}\n"), 0o644))

	// Create run-state scratch (also should be ignored).
	runStateDir := filepath.Join(root, ".ddx", "run-state")
	require.NoError(t, os.MkdirAll(runStateDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(runStateDir, "attempt.json"), []byte("{}\n"), 0o644))

	// Create a real implementation file that MUST be flagged.
	require.NoError(t, os.WriteFile(filepath.Join(root, "main.go"), []byte("package main\n"), 0o644))

	paths, err := preDispatchCheckpointDirtyPaths(root)
	require.NoError(t, err)

	assert.Contains(t, paths, "main.go",
		"untracked source file must be flagged as implementation dirt")
	assert.NotContains(t, paths, ".ddx/harness-sessions/-926795.json",
		"harness-session scratch must not be flagged as implementation dirt")
	assert.NotContains(t, paths, ".ddx/run-state/attempt.json",
		"run-state scratch must not be flagged as implementation dirt")
}

